parameters.jsCode:
const input = $input.first().json;

const raw = input.texto
         || input.text
         || input.output
         || JSON.stringify(input);

const limpo = raw
  .replace(/```json/gi, "")
  .replace(/```/g, "")
  .trim();

try {
  const resultado = JSON.parse(limpo);
  const resumo = resultado.resumo || [];

  return [{ json: {
    remetente: resultado.remetente || "",
    categoria: resultado.categoria || "",
    resumo0: resumo[0] || "",
    resumo1: resumo[1] || "",
    resumo2: resumo[2] || "",
    resposta_sugerida: resultado.resposta_sugerida || ""
  }}];
} catch (e) {
  return [{ json: { erro: e.message, texto_original: limpo } }];
}

